import React, { useEffect, useRef } from "react";

function Captcha({ onChange }) {
  const canvasRef = useRef(null);

  // Generate random code: 5 characters A-Z 0-9
  const generateCode = () => {
    const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
    let result = "";
    for (let i = 0; i < 5; i++) {
      result += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    return result;
  };

  // Draw distorted text on canvas
  const drawCaptcha = (text) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    ctx.clearRect(0, 0, 150, 50);

    ctx.fillStyle = "#f0f0f0";
    ctx.fillRect(0, 0, 150, 50);

    for (let i = 0; i < 5; i++) {
      ctx.strokeStyle = `rgba(0,0,0,${Math.random()})`;
      ctx.beginPath();
      ctx.moveTo(Math.random() * 150, Math.random() * 50);
      ctx.lineTo(Math.random() * 150, Math.random() * 50);
      ctx.stroke();
    }

    for (let i = 0; i < text.length; i++) {
      const letter = text[i];
      ctx.font = "26px Arial";
      ctx.fillStyle = `rgb(${Math.floor(Math.random() * 100)}, 0, 0)`;
      const x = 20 + i * 25;
      const y = 30 + (Math.random() * 10 - 5);
      const angle = (Math.random() - 0.5) * 0.5;

      ctx.save();
      ctx.translate(x, y);
      ctx.rotate(angle);
      ctx.fillText(letter, 0, 0);
      ctx.restore();
    }
  };

  // Refresh captcha and notify parent
  const refreshCaptcha = () => {
    const newCode = generateCode();
    drawCaptcha(newCode);
    if (onChange) onChange(newCode);
  };

  React.useEffect(() => {
    refreshCaptcha();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return (
    <div>
      <canvas
        ref={canvasRef}
        width={150}
        height={50}
        style={{ border: "1px solid #ccc", cursor: "pointer" }}
        onClick={refreshCaptcha}
        title="Click to refresh captcha"
      />
      <button
        type="button"
        className="btn btn-link p-0 mt-1"
        onClick={refreshCaptcha}
      >
        Refresh Captcha
      </button>
    </div>
  );
}

export default Captcha;
